{"command": "for file in /Users/gladyscavero/Documents/PEOPL/GitHub/claw-code/rust/crates/runtime/src/*.rs; do
  name=$(basename "$file")
  # Find all functions and estimate their line counts
  awk '
    /^[[:space:]]*(pub[[:space:]]+)?(async[[:space:]]+)?fn/ {
      fn_start = NR
      fn_name = $0
      getline
      line_count = 0
      bracket_depth = 0
      started = 0

      while (getline > 0) {
        line_count++
        # Count opening and closing brackets
        for (i = 1; i <= length($0); i++) {
          c = substr($0, i, 1)
          if (c == "{") bracket_depth++
          if (c == "}") bracket_depth--
        }
        if (bracket_depth == 0 && started) {
          print fn_start, fn_start+line_count, line_count, "'$name'", fn_name
          next
        }
        if (bracket_depth > 0) started = 1
      }
    }
  ' "$file"
done | sort -k3 -rn | head -50"}
